mapper.select:
SELECT fm.* FROM favorite_manuscripts fm
JOIN favorite_folders ff ON fm.folder_id = ff.id
WHERE ff.user_id = #{userId} AND fm.manuscript_id = #{manuscriptId}

SELECT m.* FROM favorite_manuscripts fm
JOIN manuscripts m ON fm.manuscript_id = m.id
WHERE fm.folder_id = #{folderId}
ORDER BY fm.created_at ${sortOrder}
LIMIT #{offset}, #{size}
